package April_7;
import java.util.*;
public class PrintStartToEnd {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		Scanner sc = new Scanner(System.in);
		int a = sc.nextInt();
		int b = sc.nextInt();
		
		for(int i =a;i<=b;i++) {
			System.out.println(i);
		}

	}

}
